  ('f89cefa5-e186-4b53-8337-05ee43df2218', 'Kannst du das bitte wiederholen?', 'Can you please repeat that?', 'هل يمكنك تكرار ذلك من فضلك؟', 'Used in Umwelt und Natur', 'formal', false, NULL, 2),
  ('f89cefa5-e186-4b53-8337-05ee43df2218', 'Ich habe alles verstanden.', 'I understood everything.', 'لقد فهمت كل شيء.', 'Used in Umwelt und Natur', 'neutral', false, NULL, 3),
  ('f89cefa5-e186-4b53-8337-05ee43df2218', 'Das ist eine gute Übung.', 'That is a good exercise.', 'هذا تمرين جيد.', 'Used in Umwelt und Natur', 'neutral', false, NULL, 4),
  ('f89cefa5-e186-4b53-8337-05ee43df2218', 'Noch einmal, bitte!', 'Once more, please!', 'مرة أخرى من فضلك!', 'Used in Umwelt und Natur', 'formal', false, NULL, 5);
